import { useMemo, useState, useEffect } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces, cities, types } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';
import MapView from '../components/MapView';
import Filters from '../components/Filters';
import searchImage from '../images/infralist-com-kmIKEGO7Vl4-unsplash.jpg';

function useFavorites() {
  const [fav, setFav] = useState(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      return raw ? JSON.parse(raw) : [];
    } catch {
      return [];
    }
  });
  useEffect(() => {
    localStorage.setItem('wn:favorites', JSON.stringify(fav));
  }, [fav]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}

export default function Search() {
  const [filterValues, setFilterValues] = useState({ city: '', type: '', minPrice: '', maxPrice: '' });
  const { favorites, toggle } = useFavorites();
  const [sortBy, setSortBy] = useState('relevance');
  const [showMap, setShowMap] = useState(false);
  const [homeCity, setHomeCity] = useState(() => {
    try {
      return localStorage.getItem('wn:homeCity') || '';
    } catch { return ''; }
  });
  useEffect(() => {
    localStorage.setItem('wn:homeCity', homeCity);
  }, [homeCity]);

  const filtered = useMemo(() => {
    let result = spaces.filter((s) => {
      if (filterValues.city && s.city !== filterValues.city) return false;
      if (filterValues.type && s.type !== filterValues.type) return false;
      if (filterValues.minPrice && s.pricePerDay < Number(filterValues.minPrice)) return false;
      if (filterValues.maxPrice && s.pricePerDay > Number(filterValues.maxPrice)) return false;
      return true;
    });
    if (sortBy === 'price-asc') result = [...result].sort((a, b) => a.pricePerDay - b.pricePerDay);
    if (sortBy === 'price-desc') result = [...result].sort((a, b) => b.pricePerDay - a.pricePerDay);
    if (sortBy === 'rating-desc') result = [...result].sort((a, b) => b.rating - a.rating);
    return result;
  }, [filterValues, sortBy]);

  const commuteFor = (s) => {
    if (!homeCity) return undefined;
    const same = s.city === homeCity;
    const min = same ? 15 : 45;
    const max = same ? 35 : 90;
    return Math.floor(Math.random() * (max - min + 1)) + min;
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <Navbar />
      <main className="flex-1">
        {/* Hero Section */}
        <section className="relative h-[50vh] min-h-[400px] flex items-center justify-center overflow-hidden">
          <div className="absolute inset-0">
            <img 
              src={searchImage} 
              alt="Explore Workspaces" 
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-r from-gray-900/80 via-gray-900/70 to-gray-900/60"></div>
          </div>
          
          <div className="relative z-10 max-w-7xl mx-auto px-6 md:px-12 lg:px-16 text-center text-white">
            <h1 className="text-4xl md:text-6xl font-bold mb-4">
              Explore <span className="text-blue-400">Workspaces</span>
            </h1>
            <p className="text-xl text-gray-200 mb-8">Find the perfect space for your team</p>
            
            <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
              <div className="flex items-center gap-3 px-5 py-3 bg-white/10 backdrop-blur-md border border-white/20 rounded-lg">
                <div className="w-10 h-10 rounded-lg bg-blue-600 flex items-center justify-center">
                  <span className="text-white font-bold">{filtered.length}</span>
                </div>
                <span className="font-semibold">results found</span>
              </div>
              
              <select
                className="h-12 px-5 rounded-lg border border-white/20 bg-white/10 backdrop-blur-md text-white font-medium focus:outline-none focus:ring-2 focus:ring-blue-500"
                value={homeCity}
                onChange={(e) => setHomeCity(e.target.value)}
              >
                <option value="" className="text-gray-900">Commute from</option>
                {cities.map((c) => (
                  <option key={c} value={c} className="text-gray-900">{c}</option>
                ))}
              </select>
              
              <select
                className="h-12 px-5 rounded-lg border border-white/20 bg-white/10 backdrop-blur-md text-white font-medium focus:outline-none focus:ring-2 focus:ring-blue-500"
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
              >
                <option value="relevance" className="text-gray-900">Sort: Relevance</option>
                <option value="price-asc" className="text-gray-900">Price: Low to High</option>
                <option value="price-desc" className="text-gray-900">Price: High to Low</option>
                <option value="rating-desc" className="text-gray-900">Rating: High to Low</option>
              </select>
              
              <button
                className={`h-12 px-6 rounded-lg font-semibold transition-all ${
                  showMap 
                    ? 'bg-blue-600 text-white' 
                    : 'bg-white/10 backdrop-blur-md border border-white/20 text-white hover:bg-white/20'
                }`}
                onClick={() => setShowMap(!showMap)}
              >
                {showMap ? 'List View' : 'Map View'}
              </button>
            </div>
          </div>
        </section>

        {/* Filters and Results */}
        <section className="py-8">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <div className="bg-white rounded-2xl shadow-lg p-6 mb-6">
              <Filters cities={cities} types={types} values={filterValues} onChange={setFilterValues} />
            </div>

            {!showMap ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filtered.length === 0 ? (
                  <div className="col-span-full py-16 text-center">
                    <div className="w-16 h-16 mx-auto rounded-full bg-gray-100 flex items-center justify-center mb-4">
                      <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    </div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-2">No spaces found</h3>
                    <p className="text-gray-600">Try adjusting your filters to see more results.</p>
                  </div>
                ) : (
                  filtered.map((s) => (
                    <SpaceCard 
                      key={s.id} 
                      space={s} 
                      onToggleFavorite={toggle} 
                      isFavorite={favorites.includes(s.id)} 
                      commuteMins={commuteFor(s)} 
                    />
                  ))
                )}
              </div>
            ) : (
              <div className="rounded-2xl overflow-hidden border border-gray-200 shadow-lg">
                <MapView spaces={filtered} />
              </div>
            )}
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
